    78→      if (!declaration) {
    79→        // don't know what the declaration is for some reason, so just assume the worst
    80→        return true;
    81→      }
    82→
    83→      if (
    84→        // non-strict mode doesn't care about used before assigned errors
    85→        tsutils.isStrictCompilerOptionEnabled(
    86→          compilerOptions,
    87→          'strictNullChecks',
    88→        ) &&
    89→        // ignore class properties as they are compile time guarded
    90→        // also ignore function arguments as they can't be used before defined
    91→        ts.isVariableDeclaration(declaration)
    92→      ) {
    93→        // For var declarations, we need to check whether the node
    94→        // is actually in a descendant of its declaration or not. If not,
    95→        // it may be used before defined.
    96→
    97→        // eg
    98→        // if (Math.random() < 0.5) {
    99→        //     var x: number  = 2;
   100→        // } else {
   101→        //     x!.toFixed();
   102→        // }
   103→        if (
   104→          ts.isVariableDeclarationList(declaration.parent) &&
   105→          // var
   106→          declaration.parent.flags === ts.NodeFlags.None &&
   107→          // If they are not in the same file it will not exist.
   108→          // This situation must not occur using before defined.
   109→          services.tsNodeToESTreeNodeMap.has(declaration)
   110→        ) {
   111→          const declaratorNode: TSESTree.VariableDeclaration =
   112→            services.tsNodeToESTreeNodeMap.get(declaration);
