   117→            if (parentScope === scope) {
   118→              return true;
   119→            }
   120→          }
   121→        }
   122→
   123→        if (
   124→          // is it `const x!: number`
   125→          declaration.initializer == null &&
   126→          declaration.exclamationToken == null &&
   127→          declaration.type != null
   128→        ) {
   129→          // check if the defined variable type has changed since assignment
   130→          const declarationType = checker.getTypeFromTypeNode(declaration.type);
   131→          const type = getConstrainedTypeAtLocation(services, node);
   132→          if (
   133→            declarationType === type &&
   134→            // `declare`s are never narrowed, so never skip them
   135→            !(
   136→              ts.isVariableDeclarationList(declaration.parent) &&
   137→              ts.isVariableStatement(declaration.parent.parent) &&
   138→              tsutils.includesModifier(
   139→                getModifiers(declaration.parent.parent),
   140→                ts.SyntaxKind.DeclareKeyword,
   141→              )
   142→            )
   143→          ) {
   144→            // possibly used before assigned, so just skip it
   145→            // better to false negative and skip it, than false positive and fix to compile erroring code
   146→            //
   147→            // no better way to figure this out right now
   148→            // https://github.com/Microsoft/TypeScript/issues/31124
   149→            return true;
   150→          }
   151→        }
   152→      }
   153→      return false;
   154→    }
   155→
   156→    function isConstAssertion(node: TSESTree.TypeNode): boolean {
   157→      return (
   158→        node.type === AST_NODE_TYPES.TSTypeReference &&
   159→        node.typeName.type === AST_NODE_TYPES.Identifier &&
   160→        node.typeName.name === 'const'
   161→      );
   162→    }
   163→
   164→    function isTemplateLiteralWithExpressions(expression: TSESTree.Expression) {
   165→      return (
   166→        expression.type === AST_NODE_TYPES.TemplateLiteral &&
   167→        expression.expressions.length !== 0
   168→      );
   169→    }
   170→
   171→    function isImplicitlyNarrowedLiteralDeclaration({
   172→      expression,
   173→      parent,
   174→    }: TSESTree.TSAsExpression | TSESTree.TSTypeAssertion): boolean {
