   176→       * Even on `const` variable declarations, template literals with expressions can sometimes be widened without a type assertion.
   177→       * @see https://github.com/typescript-eslint/typescript-eslint/issues/8737
   178→       */
   179→      if (isTemplateLiteralWithExpressions(expression)) {
   180→        return false;
   181→      }
   182→
   183→      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
   184→      const maybeDeclarationNode = parent.parent!;
   185→
   186→      return (
   187→        (maybeDeclarationNode.type === AST_NODE_TYPES.VariableDeclaration &&
   188→          maybeDeclarationNode.kind === 'const') ||
   189→        (parent.type === AST_NODE_TYPES.PropertyDefinition && parent.readonly)
   190→      );
   191→    }
   192→
   193→    function isTypeUnchanged(uncast: ts.Type, cast: ts.Type): boolean {
   194→      if (uncast === cast) {
   195→        return true;
   196→      }
   197→
   198→      if (
   199→        isTypeFlagSet(uncast, ts.TypeFlags.Undefined) &&
   200→        isTypeFlagSet(cast, ts.TypeFlags.Undefined) &&
   201→        tsutils.isCompilerOptionEnabled(
   202→          compilerOptions,
   203→          'exactOptionalPropertyTypes',
   204→        )
   205→      ) {
   206→        const uncastParts = tsutils
   207→          .unionConstituents(uncast)
   208→          .filter(part => !isTypeFlagSet(part, ts.TypeFlags.Undefined));
   209→
   210→        const castParts = tsutils
   211→          .unionConstituents(cast)
   212→          .filter(part => !isTypeFlagSet(part, ts.TypeFlags.Undefined));
   213→
   214→        if (uncastParts.length !== castParts.length) {
   215→          return false;
   216→        }
   217→
   218→        const uncastPartsSet = new Set(uncastParts);
   219→        return castParts.every(part => uncastPartsSet.has(part));
   220→      }
   221→
   222→      return false;
   223→    }
   224→
   225→    function isTypeLiteral(type: ts.Type) {
   226→      return type.isLiteral() || tsutils.isBooleanLiteralType(type);
   227→    }
   228→
   229→    function isIIFE(
   230→      expression: TSESTree.Expression,
   231→    ): expression is TSESTree.CallExpression & {
   232→      callee: TSESTree.ArrowFunctionExpression | TSESTree.FunctionExpression;
   233→    } {
   234→      return (
   235→        expression.type === AST_NODE_TYPES.CallExpression &&
   236→        (expression.callee.type === AST_NODE_TYPES.ArrowFunctionExpression ||
   237→          expression.callee.type === AST_NODE_TYPES.FunctionExpression)
   238→      );
   239→    }
   240→
   241→    function getUncastType(
   242→      node: TSESTree.TSAsExpression | TSESTree.TSTypeAssertion,
   243→    ): ts.Type {
   244→      // Special handling for IIFE: extract the function's return type
   245→      if (isIIFE(node.expression)) {
   246→        const callee = node.expression.callee;
   247→        const functionType = services.getTypeAtLocation(callee);
   248→        const signatures = functionType.getCallSignatures();
   249→
   250→        if (signatures.length > 0) {
   251→          const returnType = checker.getReturnTypeOfSignature(signatures[0]);
