   253→          // If the function has no explicit return type annotation and returns undefined,
   254→          // treat it as void (TypeScript infers () => {} as () => undefined, but it should be void)
   255→          if (
   256→            callee.returnType == null &&
   257→            isTypeFlagSet(returnType, ts.TypeFlags.Undefined)
   258→          ) {
   259→            return checker.getVoidType();
   260→          }
   261→
   262→          return returnType;
   263→        }
   264→      }
   265→
   266→      return services.getTypeAtLocation(node.expression);
   267→    }
   268→
   269→    return {
   270→      'TSAsExpression, TSTypeAssertion'(
   271→        node: TSESTree.TSAsExpression | TSESTree.TSTypeAssertion,
   272→      ): void {
   273→        if (
   274→          options.typesToIgnore?.includes(
   275→            context.sourceCode.getText(node.typeAnnotation),
   276→          )
   277→        ) {
   278→          return;
   279→        }
   280→
   281→        const castType = services.getTypeAtLocation(node);
   282→        const castTypeIsLiteral = isTypeLiteral(castType);
   283→        const typeAnnotationIsConstAssertion = isConstAssertion(
   284→          node.typeAnnotation,
   285→        );
   286→
   287→        if (
   288→          !options.checkLiteralConstAssertions &&
   289→          castTypeIsLiteral &&
   290→          typeAnnotationIsConstAssertion
   291→        ) {
   292→          return;
   293→        }
   294→
   295→        const uncastType = getUncastType(node);
   296→
   297→        const typeIsUnchanged = isTypeUnchanged(uncastType, castType);
   298→        const wouldSameTypeBeInferred = castTypeIsLiteral
   299→          ? isImplicitlyNarrowedLiteralDeclaration(node)
   300→          : !typeAnnotationIsConstAssertion;
